mapper.select:
SELECT r.id, r.reporter_id AS reporterId, COALESCE(NULLIF(ru.nickname,''), NULLIF(ru.username,''), '匿名') AS reporterName, r.target_type AS targetType, r.target_id AS targetId, r.reason, r.description, r.status, r.handler_id AS handlerId, COALESCE(NULLIF(hu.nickname,''), NULLIF(hu.username,''), NULL) AS handlerName, r.handle_note AS handleNote, r.create_time AS createTime, r.update_time AS updateTime FROM content_report r LEFT JOIN user_account ru ON ru.id = r.reporter_id LEFT JOIN user_account hu ON hu.id = r.handler_id
AND r.status = #{status}
ORDER BY r.create_time DESC LIMIT #{limit} OFFSET #{offset}
